<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Kanban Board</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f4f6f8;
      --surface: #ffffff;
      --border: #e2e8f0;
      --text: #172033;
      --muted: #64748b;
      --accent: #4f46e5;
      --accent-dark: #3730a3;
      --shadow: 0 10px 25px rgba(15, 23, 42, 0.07);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
        "Segoe UI", sans-serif;
      color: var(--text);
      background: linear-gradient(135deg, #eef2ff, var(--bg) 42%);
    }

    .app {
      width: min(1180px, calc(100% - 32px));
      margin: 0 auto;
      padding: 44px 0 56px;
    }

    .topbar {
      display: flex;
      align-items: end;
      justify-content: space-between;
      gap: 24px;
      margin-bottom: 32px;
    }

    h1 {
      margin: 0 0 8px;
      font-size: clamp(2rem, 4vw, 3rem);
      letter-spacing: -0.045em;
    }

    .subtitle {
      margin: 0;
      color: var(--muted);
      font-size: 1rem;
    }

    .composer {
      display: flex;
      width: min(100%, 430px);
      gap: 10px;
    }

    #new-card {
      flex: 1;
      min-width: 0;
      padding: 13px 15px;
      border: 1px solid var(--border);
      border-radius: 10px;
      outline: none;
      background: var(--surface);
      color: var(--text);
      font: inherit;
      box-shadow: 0 3px 10px rgba(15, 23, 42, 0.04);
    }

    #new-card:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.14);
    }

    #add-card {
      border: 0;
      border-radius: 10px;
      padding: 0 18px;
      background: var(--accent);
      color: white;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: background 0.2s ease, transform 0.2s ease;
    }

    #add-card:hover {
      background: var(--accent-dark);
      transform: translateY(-1px);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 20px;
      align-items: start;
    }

    .column {
      min-height: 450px;
      padding: 18px;
      border: 1px solid var(--border);
      border-radius: 16px;
      background: rgba(255, 255, 255, 0.76);
      box-shadow: var(--shadow);
      transition: border-color 0.2s ease, background 0.2s ease;
    }

    .column.drag-over {
      border-color: var(--accent);
      background: #f5f3ff;
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 16px;
    }

    .column-title {
      margin: 0;
      font-size: 1.05rem;
      letter-spacing: -0.01em;
    }

    .count {
      display: inline-grid;
      min-width: 28px;
      height: 28px;
      padding: 0 8px;
      place-items: center;
      border-radius: 999px;
      background: #eef2ff;
      color: var(--accent-dark);
      font-size: 0.85rem;
      font-weight: 800;
    }

    .card-container {
      display: flex;
      min-height: 370px;
      flex-direction: column;
      gap: 12px;
    }

    .card {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      padding: 15px;
      border: 1px solid var(--border);
      border-radius: 12px;
      background: var(--surface);
      box-shadow: 0 4px 12px rgba(15, 23, 42, 0.06);
      cursor: grab;
      user-select: none;
    }

    .card:active {
      cursor: grabbing;
    }

    .card.dragging {
      opacity: 0.45;
    }

    .card-title {
      overflow-wrap: anywhere;
      line-height: 1.4;
    }

    .card-del {
      flex: 0 0 auto;
      border: 0;
      border-radius: 7px;
      padding: 5px 8px;
      background: transparent;
      color: #94a3b8;
      cursor: pointer;
      font-size: 0.8rem;
      font-weight: 700;
    }

    .card-del:hover {
      background: #fee2e2;
      color: #b91c1c;
    }

    @media (max-width: 800px) {
      .topbar {
        align-items: stretch;
        flex-direction: column;
      }

      .composer {
        width: 100%;
      }

      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 250px;
      }

      .card-container {
        min-height: 120px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header class="topbar">
      <div>
        <h1>Kanban board</h1>
        <p class="subtitle">Organize work clearly, one card at a time.</p>
      </div>

      <form class="composer" id="card-form">
        <input
          id="new-card"
          type="text"
          autocomplete="off"
          placeholder="Add a new task..."
          aria-label="New card title"
        />
        <button id="add-card" type="submit">Add card</button>
      </form>
    </header>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo" data-column="todo">
        <div class="column-header">
          <h2 class="column-title">To Do</h2>
          <span class="count" aria-label="To Do card count">0</span>
        </div>
        <div class="card-container" aria-label="To Do cards"></div>
      </section>

      <section class="column" id="col-doing" data-column="doing">
        <div class="column-header">
          <h2 class="column-title">In Progress</h2>
          <span class="count" aria-label="In Progress card count">0</span>
        </div>
        <div class="card-container" aria-label="In Progress cards"></div>
      </section>

      <section class="column" id="col-done" data-column="done">
        <div class="column-header">
          <h2 class="column-title">Done</h2>
          <span class="count" aria-label="Done card count">0</span>
        </div>
        <div class="card-container" aria-label="Done cards"></div>
      </section>
    </section>
  </main>

  <script>
    (() => {
      const STORAGE_KEY = "kanban-board-state";
      const columnNames = ["todo", "doing", "done"];
      let draggedCard = null;

      const getColumn = (name) =>
        document.querySelector('[data-column="' + name + '"]');

      const createId = () =>
        "card-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 9);

      function saveBoard() {
        const state = {};
        columnNames.forEach((name) => {
          state[name] = [...getColumn(name).querySelectorAll(".card")].map((card) => ({
            id: card.dataset.cardId,
            title: card.querySelector(".card-title").textContent
          }));
        });
        localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      }

      function updateCounts() {
        columnNames.forEach((name) => {
          const column = getColumn(name);
          column.querySelector(".count").textContent =
            column.querySelectorAll(".card").length;
        });
      }

      function deleteCard(card) {
        card.remove();
        updateCounts();
        saveBoard();
      }

      function makeCard(title, id = createId()) {
        const card = document.createElement("article");
        card.className = "card";
        card.draggable = true;
        card.dataset.cardId = id;

        const titleElement = document.createElement("span");
        titleElement.className = "card-title";
        titleElement.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.textContent = "Delete";
        deleteButton.setAttribute("aria-label", "Delete " + title);
        deleteButton.addEventListener("click", (event) => {
          event.stopPropagation();
          deleteCard(card);
        });

        card.append(titleElement, deleteButton);

        card.addEventListener("dragstart", (event) => {
          draggedCard = card;
          card.classList.add("dragging");
          event.dataTransfer.effectAllowed = "move";
          event.dataTransfer.setData("text/plain", card.dataset.cardId);
        });

        card.addEventListener("dragend", () => {
          card.classList.remove("dragging");
          draggedCard = null;
          document.querySelectorAll(".column").forEach((column) => {
            column.classList.remove("drag-over");
          });
        });

        return card;
      }

      function loadBoard() {
        let saved = null;
        try {
          saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
        } catch (error) {
          saved = null;
        }

        if (!saved || typeof saved !== "object") {
          updateCounts();
          return;
        }

        columnNames.forEach((name) => {
          const cards = Array.isArray(saved[name]) ? saved[name] : [];
          const container = getColumn(name).querySelector(".card-container");

          cards.forEach((item) => {
            if (item && typeof item.title === "string") {
              container.appendChild(makeCard(item.title, item.id || createId()));
            }
          });
        });

        updateCounts();
      }

      document.querySelectorAll(".column").forEach((column) => {
        column.addEventListener("dragover", (event) => {
          event.preventDefault();
          event.dataTransfer.dropEffect = "move";
          column.classList.add("drag-over");
        });

        column.addEventListener("dragleave", (event) => {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", (event) => {
          event.preventDefault();
          column.classList.remove("drag-over");

          const cardId = event.dataTransfer.getData("text/plain");
          const card = draggedCard || document.querySelector(`[data-card-id="${cardId}"]`);

          if (card) {
            column.querySelector(".card-container").appendChild(card);
            updateCounts();
            saveBoard();
          }
        });
      });

      document.getElementById("card-form").addEventListener("submit", (event) => {
        event.preventDefault();

        const input = document.getElementById("new-card");
        const title = input.value.trim();

        if (!title) {
          return;
        }

        getColumn("todo")
          .querySelector(".card-container")
          .appendChild(makeCard(title));

        input.value = "";
        updateCounts();
        saveBoard();
        input.focus();
      });

      loadBoard();
    })();
  </script>
</body>
</html>
